const { checks, timestamp } = $input.first().json;

const results = [];

for (const check of checks) {
  const start = Date.now();
  let status = 'unknown';
  let responseTime = 0;
  let statusCode = 0;
  let error = null;

  if (check.tcpCheck) {
    // TCP-only services (Postgres, Redis) - just mark as needing Docker check
    status = 'check-via-docker';
    responseTime = 0;
  } else {
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 8000);

      const opts = {
        method: check.method || 'GET',
        signal: controller.signal,
        headers: check.headers || {},
      };
      if (check.body) opts.body = check.body;

      const response = await fetch(check.url, opts);
      clearTimeout(timeout);

      statusCode = response.status;
      responseTime = Date.now() - start;

      if (statusCode >= 200 && statusCode < 400) {
        status = 'healthy';
      } else if (statusCode >= 400 && statusCode < 500) {
        status = 'degraded';
      } else {
        status = 'unhealthy';
      }
    } catch (err) {
      responseTime = Date.now() - start;
      error = err.message || 'Connection failed';

      if (error.includes('abort') || error.includes('timeout')) {
        status = 'timeout';
      } else if (error.includes('ECONNREFUSED') || error.includes('fetch failed')) {
        status = 'down';
      } else {
        status = 'error';
      }
    }
  }

  results.push({
    name: check.name,
    type: check.type,
    critical: check.critical,
    status,
    statusCode,
    responseTime,
    error,
    url: check.url,
  });
}

// Calculate overall health
const healthy = results.filter(r => r.status === 'healthy').length;
const criticalDown = results.filter(r => r.critical && ['down', 'error', 'timeout', 'unhealthy'].includes(r.status));
